import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Lock, Mail, Eye, EyeOff, ArrowRight } from 'lucide-react';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../services/firebase';
import farmBg from '../images/LoginBackground.jpg';

const LOGO_B64 = "data:image/png;base64,";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Lora:wght@400;600;700&family=Source+Sans+3:wght@400;500;600&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
 .login-root {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: #f5f0e8;

  background-image:
    linear-gradient(rgba(245,240,232,0.85), rgba(245,240,232,0.85)),
    url(${farmBg});

  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;

  font-family: 'Source Sans 3', sans-serif;
  padding: 20px;
}
  .login-card {
    background: #fff; border-radius: 20px; width: 100%; max-width: 440px;
    padding: 48px 40px 40px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.04), 0 12px 40px rgba(46,125,50,0.10), 0 0 0 1px rgba(46,125,50,0.06);
    position: relative; overflow: hidden;
    animation: fadeUp 0.5s ease both;
  }
  @keyframes fadeUp { from { opacity:0; transform:translateY(18px); } to { opacity:1; transform:translateY(0); } }
  .login-card::before {
    content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px;
    background: linear-gradient(90deg, #2E7D32, #689F38, #2E7D32);
  }
  .logo-area { display: flex; flex-direction: column; align-items: center; margin-bottom: 32px; text-align: center; }
  .logo-circle {
    width: 90px; height: 90px; border-radius: 50%; background: #E8F5E9;
    border: 2px solid rgba(46,125,50,0.20); display: flex; align-items: center;
    justify-content: center; margin-bottom: 16px;
    box-shadow: 0 4px 20px rgba(46,125,50,0.18); overflow: hidden; padding: 6px;
  }
  .logo-circle img { width: 100%; height: 100%; object-fit: contain; }
  .logo-area h1 { font-family: 'Lora', serif; font-size: 26px; font-weight: 700; color: #1b1b1b; letter-spacing: -0.3px; }
  .logo-area p { font-size: 14px; color: #6b7280; margin-top: 4px; }
  .divider-line { height: 1px; background: #f0ebe0; margin-bottom: 28px; }
  .error-box {
    background: #fff5f5; border: 1px solid #fca5a5; border-left: 3px solid #ef4444;
    border-radius: 8px; padding: 10px 14px; font-size: 13.5px; color: #b91c1c;
    margin-bottom: 20px; line-height: 1.4;
  }
  .field-group { margin-bottom: 18px; }
  .field-label { display: block; font-size: 13.5px; font-weight: 600; color: #374151; margin-bottom: 7px; }
  .input-wrap { position: relative; display: flex; align-items: center; }
  .input-icon { position: absolute; left: 13px; color: #9ca3af; pointer-events: none; display: flex; }
  .input-wrap input {
    width: 100%; padding: 11px 42px 11px 40px; border: 1.5px solid #d1d5db;
    border-radius: 10px; font-size: 15px; font-family: 'Source Sans 3', sans-serif;
    color: #1f2937; background: #fafaf8; transition: border-color 0.2s, box-shadow 0.2s; outline: none;
  }
  .input-wrap input::placeholder { color: #c0bdb5; }
  .input-wrap input:focus { border-color: #2E7D32; background: #fff; box-shadow: 0 0 0 3px rgba(46,125,50,0.10); }
  .pw-toggle { position: absolute; right: 12px; background: none; border: none; cursor: pointer; color: #9ca3af; display: flex; padding: 4px; border-radius: 4px; transition: color 0.2s; }
  .pw-toggle:hover { color: #6b7280; }
  .form-row { display: flex; align-items: center; justify-content: space-between; margin-bottom: 24px; margin-top: 4px; }
  .remember-label { display: flex; align-items: center; gap: 7px; cursor: pointer; font-size: 14px; color: #4b5563; user-select: none; }
  .remember-label input[type="checkbox"] { width: 16px; height: 16px; accent-color: #2E7D32; cursor: pointer; }
  .forgot-link { font-size: 14px; color: #2E7D32; font-weight: 600; text-decoration: none; transition: color 0.2s; }
  .forgot-link:hover { color: #1b5e20; text-decoration: underline; }
  .btn-login {
    width: 100%; padding: 13px 20px; background: #2E7D32; color: #fff; border: none;
    border-radius: 28px; font-size: 16px; font-weight: 600; font-family: 'Source Sans 3', sans-serif;
    cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 8px;
    letter-spacing: 0.3px; transition: background 0.2s, transform 0.1s, box-shadow 0.2s;
    box-shadow: 0 4px 16px rgba(46,125,50,0.28);
  }
  .btn-login:hover:not(:disabled) { background: #1b5e20; box-shadow: 0 6px 20px rgba(46,125,50,0.35); }
  .btn-login:active:not(:disabled) { transform: scale(0.99); }
  .btn-login:disabled { background: rgba(46,125,50,0.55); cursor: not-allowed; box-shadow: none; }
  .spinner { width: 18px; height: 18px; border: 2.5px solid rgba(255,255,255,0.4); border-top-color: #fff; border-radius: 50%; animation: spin 0.7s linear infinite; }
  @keyframes spin { to { transform: rotate(360deg); } }
  .card-footer {
    margin-top: 22px; padding-top: 18px; border-top: 1px solid #f0ebe0;
    text-align: center; font-size: 12.5px; color: #9ca3af;
    display: flex; align-items: center; justify-content: center; gap: 6px;
  }
  .card-footer svg { color: #2E7D32; }
`;

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      if (!email || !password) { setError('Please enter both email and password.'); setLoading(false); return; }
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const idToken = await userCredential.user.getIdToken();
      if (idToken) { localStorage.setItem('token', idToken); navigate('/dashboard'); }
      else { setError('Failed to retrieve authentication token.'); }
    } catch (err) {
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password') {
        setError('Invalid email or password. Please try again.');
      } else if (err.code === 'auth/too-many-requests') {
        setError('Too many failed attempts. Please try again later.');
      } else {
        setError('Login failed. Please check your connection and try again.');
      }
    } finally { setLoading(false); }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="login-root">
        <div className="login-card">
          <div className="logo-area">
            <div className="logo-circle">
              <img src={LOGO_B64} alt="CeylonPepper Logo" />
            </div>
            <h1>Farm Admin Portal</h1>
            <p>Secure access for farm administrators</p>
          </div>
          <div className="divider-line" />
          <form onSubmit={handleLogin}>
            {error && <div className="error-box">{error}</div>}
            <div className="field-group">
              <label className="field-label" htmlFor="email">Email Address</label>
              <div className="input-wrap">
                <span className="input-icon"><Mail size={17} /></span>
                <input id="email" type="email" placeholder="admin@farm.com" value={email} onChange={(e) => setEmail(e.target.value)} required autoComplete="email" />
              </div>
            </div>
            <div className="field-group">
              <label className="field-label" htmlFor="password">Password</label>
              <div className="input-wrap">
                <span className="input-icon"><Lock size={17} /></span>
                <input id="password" type={showPassword ? 'text' : 'password'} placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} required autoComplete="current-password" />
                <button type="button" className="pw-toggle" onClick={() => setShowPassword(!showPassword)} aria-label={showPassword ? 'Hide password' : 'Show password'}>
                  {showPassword ? <EyeOff size={17} /> : <Eye size={17} />}
                </button>
              </div>
            </div>
            <div className="form-row">
              <label className="remember-label">
                <input type="checkbox" checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} /> Remember me
              </label>
              <Link to="/forgot-password" className="forgot-link">Forgot password?</Link>
            </div>
            <button type="submit" className="btn-login" disabled={loading}>
              {loading ? (<><div className="spinner" /> Signing in...</>) : (<>Sign In <ArrowRight size={17} /></>)}
            </button>
          </form>
          <div className="card-footer">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 20A7 7 0 0 1 9.8 6.1C15.5 5 17 4.48 19 2c1 2 2 4.18 2 8 0 5.5-4.78 10-10 10Z"/><path d="M2 21c0-3 1.85-5.36 5.08-6C9.5 14.52 12 13 13 12"/></svg>
            CeylonPepper Admin — Secure Portal
          </div>
        </div>
      </div>
    </>
  );
}